/**
 * @beta
 * 在声音定义中声明的持续时间元数据。
 *
 * Duration metadata declared in a sound definition.
 */
export interface SoundDefinitionDurationInfo {
    /**
     * @remarks
     * 声音定义中声明的总持续时长（以秒为单位）。
     *
     * Total duration of the sound in seconds, as declared in the
     * sound definition.
     *
     */
    duration: number;
}
